module RefModule(
  input [3:0] in1,
  input [3:0] in2,
  output eq,
  output gt,
  output lt
);  wire _n01 = in1[0] ^ in2[0];
  wire _n02 = in1[1] ^ in2[1];
  wire _n03 = in1[2] ^ in2[2];
  wire _n04 = in1[3] ^ in2[3];
  assign eq = ~_n01 & ~_n02 & ~_n03 & ~_n04;
  assign gt = (in1 > in2);
  assign lt = (in1 < in2);

endmodule
